function dfs(graph: Map<number, number[]>, start: number): number[] {
  const visited: Set<number> = new Set();
  const order: number[] = [];
  function visit(node: number): void {
    visited.add(node);
    order.push(node);
    for (const neighbor of graph.get(node) ?? []) {
      if (!visited.has(neighbor)) visit(neighbor);
    }
  }
  visit(start);
  return order;
}

const graph: Map<number, number[]> = new Map([
  [0, [1, 2]], [1, [0, 3]], [2, [0]], [3, [1]]
]);
console.log(dfs(graph, 0));  // [0, 1, 3, 2]

