function hasCycle(n: number, edges: [number, number][]): boolean {
  const graph: Map<number, number[]> = new Map();
  for (let i = 0; i < n; i++) graph.set(i, []);
  for (const [u, v] of edges) {
    graph.get(u)!.push(v);
    graph.get(v)!.push(u);
  }
  const visited: Set<number> = new Set();
  function dfs(node: number, parent: number): boolean {
    visited.add(node);
    for (const neighbor of graph.get(node)!) {
      if (!visited.has(neighbor)) {
        if (dfs(neighbor, node)) return true;
      } else if (neighbor !== parent) {
        return true;
      }
    }
    return false;
  }
  for (let i = 0; i < n; i++) {
    if (!visited.has(i) && dfs(i, -1)) return true;
  }
  return false;
}

console.log(hasCycle(4, [[0,1],[1,2],[2,0]]));  // true
console.log(hasCycle(4, [[0,1],[1,2],[2,3]]));  // false

